# 파일 영구 삭제 스크립트

```python
import os
import random

def secure_delete(file_path: str) -> bool:
    # Step 1: 파일 존재 여부 확인
    if not os.path.exists(file_path):
        return False

    # Step 2: 파일 크기 가져오기
    file_size = os.path.getsize(file_path)

    # Step 3: 랜덤 데이터로 덮어쓰기 (3회 반복)
    with open(file_path, 'wb') as f:
        for _ in range(3):
            f.seek(0)
            f.write(random.randbytes(file_size))

    # Step 4: 0으로 덮어쓰기
    with open(file_path, 'wb') as f:
        f.write(b'\x00' * file_size)

    # Step 5: 파일 이름 변경 (메타데이터 혼란)
    dir_name = os.path.dirname(file_path)
    temp_name = os.path.join(dir_name, 'deleted_' + str(random.randint(10000, 99999)))
    os.rename(file_path, temp_name)

    # Step 6: 파일 삭제
    os.remove(temp_name)
    return True
