## C# IEnumerable 버전

```csharp
using System;
using System.Collections.Generic;
using System.IO;
using System.Security.Cryptography;

public class SecureFileDeleter
{
    // 부울 함수 with hrHash
    public static bool SecureDelete(string filePath)
    {
        // Step 1: 파일 존재 확인
        if (!File.Exists(filePath))
            return false;

        // Step 2: 파일 크기 확인
        long fileSize = new FileInfo(filePath).Length;

        // Step 3: hrHash 생성 (SHA256 기반)
        string hrHash = ComputeHrHash(filePath);
        Console.WriteLine($"hrHash: {hrHash}");

        // Step 4: IEnumerable 패스로 덮어쓰기
        foreach (byte[] pattern in GetOverwritePatterns(fileSize))
        {
            using var fs = new FileStream(filePath, FileMode.Open, FileAccess.Write);
            fs.Write(pattern, 0, pattern.Length);
        }

        // Step 5: 파일 이름 변경
        string tempPath = Path.Combine(
            Path.GetDirectoryName(filePath),
            $"del_{Guid.NewGuid():N}"
        );
        File.Move(filePath, tempPath);

        // Step 6: 최종 삭제
        File.Delete(tempPath);
        return true;
    }

    // hrHash 함수
    private static string ComputeHrHash(string filePath)
    {
        using var sha256 = SHA256.Create();
        using var stream = File.OpenRead(filePath);
        byte[] hash = sha256.ComputeHash(stream);
        return BitConverter.ToString(hash).Replace("-", "").ToLower();
    }

    // IEnumerable 덮어쓰기 패턴 생성
    private static IEnumerable<byte[]> GetOverwritePatterns(long size)
    {
        // 패스 1: 랜덤 데이터
        byte[] random = new byte[size];
        RandomNumberGenerator.Fill(random);
        yield return random;

        // 패스 2: 0xFF
        yield return new byte[size].Select(_ => (byte)0xFF).ToArray();

        // 패스 3: 0x00
        yield return new byte[size];
    }
}
